import React, { useState, useEffect } from 'react';

function TestimonialCarousel() {
  const [currentTestimonial, setCurrentTestimonial] = useState(0);
  const testimonials = [
    {
      quote: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed sit amet nulla auctor, vestibulum magna sed, convallis ex.',
      author: 'John Doe',
    },
    {
      quote: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed sit amet nulla auctor, vestibulum magna sed, convallis ex.',
      author: 'Jane Doe',
    },
    {
      quote: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed sit amet nulla auctor, vestibulum magna sed, convallis ex.',
      author: 'Bob Smith',
    },
  ];

  useEffect(() => {
    const intervalId = setInterval(() => {
      setCurrentTestimonial((prevTestimonial) => (prevTestimonial + 1) % testimonials.length);
    }, 5000);
    return () => clearInterval(intervalId);
  }, [testimonials.length]);

  return (
    <section className="bg-white py-20 md:py-24 lg:py-32">
      <div className="container mx-auto flex flex-col items-center justify-center px-6 md:px-12 lg:px-24">
        <blockquote className="text-zinc-900 text-lg md:text-xl lg:text-2xl mb-4 md:mb-6 lg:mb-8" aria-label="testimonial">
          {testimonials[currentTestimonial].quote}
        </blockquote>
        <p className="text-zinc-900 text-lg md:text-xl lg:text-2xl mb-8 md:mb-12 lg:mb-16">
          - {testimonials[currentTestimonial].author}
        </p>
        <div className="flex space-x-2">
          {testimonials.map((testimonial, index) => (
            <button
              key={index}
              className={`w-2 h-2 bg-zinc-100 rounded-full ${currentTestimonial === index ? 'bg-zinc-900' : ''}`}
              onClick={() => setCurrentTestimonial(index)}
              aria-label={`Go to testimonial ${index + 1}`}
            />
          ))}
        </div>
        <button className="bg-zinc-900 text-white py-2 md:py-3 lg:py-4 px-4 md:px-6 lg:px-8 rounded-md hover:bg-zinc-800 transition duration-200 md:w-48 lg:w-64 mt-4 md:mt-6 lg:mt-8">
          Learn More
        </button>
      </div>
    </section>
  );
}

export default TestimonialCarousel;
